def range_summary(nums):
    if not nums:
        return ''

    unique_nums = sorted(set(nums))
    ranges = []
    start, end = None, None

    for num in unique_nums:
        if start is None or num == end + 1:
            start, end = num, num
        else:
            ranges.append(f'{start}-{end}' if start != end else f'{start}')
            start, end = num, num

        if num == unique_nums[-1]:
            ranges.append(f'{start}-{end}' if start != end else f'{start}')

    return ','.join(ranges)
